// Re-state the per-run `forall|p|` ensures so their (auto-)triggers fire
// in this proof context for both r1 and r2 branches — z3 stalled because
// the two ensures-foralls had disjoint triggers (post1_self_.* vs
// post2_self_.*), so neither instantiated against the other.
assert(forall|p: PagePtr| #![auto]
    post1_self_.page_is_mapped(p) == pre_self_.page_is_mapped(p));
assert(forall|p: PagePtr| #![auto]
    post2_self_.page_is_mapped(p) == pre_self_.page_is_mapped(p));

assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) ==> post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    post2_self_.page_is_mapped(p) ==> post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

assert(forall|c: ContainerPtr|
    #![trigger post1_self_.get_container_owned_pages(c)]
    post1_self_.container_map_4k@.dom().contains(c) ==> post1_self_.get_container_owned_pages(c)
        =~= pre_self_.get_container_owned_pages(c));
assert(forall|c: ContainerPtr|
    #![trigger post2_self_.get_container_owned_pages(c)]
    post2_self_.container_map_4k@.dom().contains(c) ==> post2_self_.get_container_owned_pages(c)
        =~= pre_self_.get_container_owned_pages(c));

// Cross-run pointwise: page_is_mapped agrees on post1 and post2.
assert forall|p: PagePtr| #![auto]
    post1_self_.page_is_mapped(p) == post2_self_.page_is_mapped(p) by {
    assert(post1_self_.page_is_mapped(p) == pre_self_.page_is_mapped(p));
    assert(post2_self_.page_is_mapped(p) == pre_self_.page_is_mapped(p));
}

// Chain the spec-level set equalities through `pre_self_` so Verus has
// post1 == post2 at the spec-fn level via set extensionality (`=~=`).
assert(post1_self_.free_pages_2m() =~= post2_self_.free_pages_2m());
assert(post1_self_.free_pages_1g() =~= post2_self_.free_pages_1g());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());
assert(post1_self_.mapped_pages_4k() =~= post2_self_.mapped_pages_4k());
assert(post1_self_.mapped_pages_2m() =~= post2_self_.mapped_pages_2m());
assert(post1_self_.mapped_pages_1g() =~= post2_self_.mapped_pages_1g());

// Container-map domains chain the same way (ensures gives pre =~= post1
// and pre =~= post2; transitivity closes the cross-run dom equality).
assert(post1_self_.container_map_4k@.dom() =~= post2_self_.container_map_4k@.dom());
assert(post1_self_.container_map_2m@.dom() =~= post2_self_.container_map_2m@.dom());
assert(post1_self_.container_map_1g@.dom() =~= post2_self_.container_map_1g@.dom());

// Pin the 4k pre/post relationships at the spec-fn level so any later
// reasoning that needs `pre_self_.allocated_pages_4k().insert(r_.0)` or
// `pre_self_.free_pages_4k().remove(r_.0)` finds them at hand.
assert(post1_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k().insert(r1.0));
assert(post2_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k().insert(r2.0));
assert(post1_self_.free_pages_4k() =~= pre_self_.free_pages_4k().remove(r1.0));
assert(post2_self_.free_pages_4k() =~= pre_self_.free_pages_4k().remove(r2.0));
